import React, { useEffect } from 'react';
import { View, Text, StyleSheet, Dimensions } from 'react-native';
import Animated, {
  useSharedValue,
  useAnimatedStyle,
  withTiming,
  withSpring,
  runOnJS,
} from 'react-native-reanimated';
import { theme } from '../../theme';
import { Button } from '../ui/Button';
import type { CustomerScanSuccessData } from '@astrolab/shared';

const { height: SCREEN_HEIGHT } = Dimensions.get('window');

interface ScanResultProps {
  success: boolean;
  data?: CustomerScanSuccessData;
  error?: { code: string; message: string };
  onViewCard?: () => void;
  onScanAgain: () => void;
  onDismiss?: () => void;
}

export function ScanResult({
  success,
  data,
  error,
  onViewCard,
  onScanAgain,
  onDismiss,
}: ScanResultProps) {
  const translateY = useSharedValue(SCREEN_HEIGHT);

  useEffect(() => {
    translateY.value = withSpring(0, { damping: 20, stiffness: 150 });

    // Auto-dismiss after 10 seconds
    const timer = setTimeout(() => {
      if (onDismiss) {
        translateY.value = withTiming(SCREEN_HEIGHT, { duration: 300 }, () => {
          runOnJS(onDismiss)();
        });
      }
    }, 10000);

    return () => clearTimeout(timer);
  }, []);

  const animatedStyle = useAnimatedStyle(() => ({
    transform: [{ translateY: translateY.value }],
  }));

  return (
    <Animated.View style={[styles.container, animatedStyle]}>
      <View style={[styles.sheet, success ? styles.successBg : styles.errorBg]}>
        <Text style={styles.emoji}>{success ? '✅' : '❌'}</Text>

        {success && data ? (
          <>
            <Text style={styles.merchantName}>{data.merchant_name}</Text>
            <View style={styles.statsRow}>
              {data.points_earned > 0 && (
                <Text style={styles.statText}>+{data.points_earned} points</Text>
              )}
              {data.stamps_earned > 0 && (
                <Text style={styles.statText}>+{data.stamps_earned} tampon{data.stamps_earned > 1 ? 's' : ''}</Text>
              )}
            </View>
            <Text style={styles.totalText}>
              Total : {data.total_points} pts | {data.stamps_current_card}/{data.stamps_per_card} tampons
            </Text>
            {data.card_completed && (
              <View style={styles.completedBadge}>
                <Text style={styles.completedText}>🎉 Carte completee ! Recompense debloquee</Text>
              </View>
            )}
            <View style={styles.actions}>
              {onViewCard && (
                <Button title="Voir ma carte" onPress={onViewCard} style={{ flex: 1, marginRight: 8 }} />
              )}
              <Button
                title="Scanner encore"
                onPress={onScanAgain}
                variant="outline"
                style={{ flex: 1 }}
              />
            </View>
          </>
        ) : (
          <>
            <Text style={styles.errorTitle}>Scan echoue</Text>
            <Text style={styles.errorMessage}>
              {error?.message || 'Une erreur est survenue'}
            </Text>
            <Button title="Reessayer" onPress={onScanAgain} style={{ marginTop: 20 }} />
          </>
        )}
      </View>
    </Animated.View>
  );
}

const styles = StyleSheet.create({
