}

function getColorFromId(id: string): string {
  let hash = 0;
  for (let i = 0; i < id.length; i++) {
    hash = id.charCodeAt(i) + ((hash << 5) - hash);
  }
  const hue = Math.abs(hash % 360);
  return `hsl(${hue}, 65%, 55%)`;
}

export function LoyaltyCardMobile({
  merchantName,
  loyaltyType,
  totalPoints,
  stampsCurrentCard,
  stampsPerCard,
  merchantId,
