const { width: SCREEN_WIDTH } = Dimensions.get('window');

interface StampsGridMobileProps {
  total: number;
  filled: number;
  size?: number;
}

function PulsingStamp({ size }: { size: number }) {
  const animatedStyle = useAnimatedStyle(() => ({
    transform: [
      {
        scale: withRepeat(
          withSequence(
            withTiming(1.2, { duration: 500 }),
            withTiming(1, { duration: 500 })
          ),
          -1,
          false
        ),
      },
    ],
  }));

  return (
    <Animated.View
      style={[
        styles.stamp,
        styles.stampFilled,
        { width: size, height: size, borderRadius: size / 2 },
        animatedStyle,
      ]}
    />
  );
}

export function StampsGridMobile({ total, filled, size = 32 }: StampsGridMobileProps) {
  const cols = Math.min(total, Math.floor((SCREEN_WIDTH - 64) / (size + 8)));

  return (
    <View style={[styles.grid, { gap: 8 }]}>
      {Array.from({ length: total }).map((_, i) => {
        const isFilled = i < filled;
        const isLatest = i === filled - 1;

        if (isLatest) {
          return <PulsingStamp key={i} size={size} />;
        }

        return (
          <View
            key={i}
            style={[
              styles.stamp,
              isFilled ? styles.stampFilled : styles.stampEmpty,
              { width: size, height: size, borderRadius: size / 2 },
            ]}
          />
        );
      })}
    </View>
  );
}

